import org.junit.Before
import org.junit.Test
import org.mockito.Mock
import org.mockito.MockitoAnnotations
import org.mockito.kotlin.whenever
import org.wordpress.android.R
import org.wordpress.android.fluxc.store.PostSchedulingNotificationStore
import org.wordpress.android.fluxc.store.SiteStore
import org.wordpress.android.ui.posts.EditPostRepository.UpdatePostResult.NoChanges
import org.wordpress.android.ui.posts.EditPostRepository.UpdatePostResult.Updated
import org.wordpress.android.util.DateTimeUtils
import org.wordpress.android.util.LocaleManagerWrapper
import org.wordpress.android.viewmodel.ResourceProvider
import java.util.Calendar

class PublishSettingsViewModelTest {
    private lateinit var viewModel: TestPublishSettingsViewModel

    @Mock
    private lateinit var resourceProvider: ResourceProvider

    @Mock
    private lateinit var postSettingsUtils: PostSettingsUtils

    @Mock
    private lateinit var localeManagerWrapper: LocaleManagerWrapper

    @Mock
    private lateinit var postSchedulingNotificationStore: PostSchedulingNotificationStore

    @Mock
    private lateinit var siteStore: SiteStore

    @Mock
    private lateinit var editPostRepository: EditPostRepository

    private val currentCalendar = Calendar.getInstance()

    @Before
    fun setUp() {
        MockitoAnnotations.openMocks(this)

        whenever(localeManagerWrapper.getCurrentCalendar()).thenReturn(currentCalendar)
        whenever(resourceProvider.getString(R.string.immediately)).thenReturn("Immediately")

        viewModel = TestPublishSettingsViewModel(
            resourceProvider,
            postSettingsUtils,
            localeManagerWrapper,
            postSchedulingNotificationStore,
            siteStore
        )
    }

    @Test
    fun `start should not throw NPE when repository has no post`() {
        // Given: repository is not null but has no post loaded
        whenever(editPostRepository.hasPost()).thenReturn(false)

        // When: start is called with the repository
        // Then: no exception should be thrown
        viewModel.start(editPostRepository)

        // Verify that year, month, day, hour, minute are still set
        assert(viewModel.year != null)
        assert(viewModel.month != null)
        assert(viewModel.day != null)
        assert(viewModel.hour != null)
        assert(viewModel.minute != null)
    }

    @Test
    fun `start should work normally when repository has a post`() {
        // Given: repository has a post with valid date
        whenever(editPostRepository.hasPost()).thenReturn(true)
        whenever(editPostRepository.dateCreated).thenReturn("2024-01-28T10:00:00Z")

        // When: start is called with the repository
        // Then: no exception should be thrown
        viewModel.start(editPostRepository)

        // Verify that year, month, day, hour, minute are still set
        assert(viewModel.year != null)
        assert(viewModel.month != null)
        assert(viewModel.day != null)
        assert(viewModel.hour != null)
        assert(viewModel.minute != null)
    }

    @Test
    fun `start should work when repository is null`() {
        // When: start is called with null repository
        // Then: no exception should be thrown
        viewModel.start(null)

        // Verify that year, month, day, hour, minute are set to current time
        assert(viewModel.year != null)
        assert(viewModel.month != null)
        assert(viewModel.day != null)
        assert(viewModel.hour != null)
        assert(viewModel.minute != null)
    }
}

