import org.assertj.core.api.Assertions.assertThat
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import org.mockito.Mock
import org.mockito.junit.MockitoJUnitRunner
import org.mockito.kotlin.whenever
import org.wordpress.android.fluxc.model.SiteModel
import org.wordpress.android.ui.deeplinks.DeepLinkNavigator.NavigateAction
import org.wordpress.android.ui.deeplinks.DeepLinkUriUtils
import org.wordpress.android.ui.deeplinks.buildUri
import org.wordpress.android.ui.jetpackoverlay.JetpackFeatureRemovalPhaseHelper
import org.wordpress.android.ui.stats.StatsTimeframe

@RunWith(MockitoJUnitRunner::class)
class StatsLinkHandlerTrafficSubscribersTest {
    @Mock
    lateinit var deepLinkUriUtils: DeepLinkUriUtils

    @Mock
    lateinit var site: SiteModel
    private lateinit var statsLinkHandler: StatsLinkHandler

    @Mock
    private lateinit var jetpackFeatureRemovalPhaseHelper: JetpackFeatureRemovalPhaseHelper

    @Before
    fun setUp() {
        statsLinkHandler = StatsLinkHandler(deepLinkUriUtils, jetpackFeatureRemovalPhaseHelper)
    }

    @Test
    fun `opens stats screen for traffic tab when URL contains traffic parameter`() {
        val uri = buildUri(host = null, "stats", "traffic")

        val buildNavigateAction = statsLinkHandler.buildNavigateAction(uri)

        assertThat(buildNavigateAction).isEqualTo(NavigateAction.OpenStatsForTimeframe(StatsTimeframe.TRAFFIC))
    }

    @Test
    fun `opens stats screen for subscribers tab when URL contains subscribers parameter`() {
        val uri = buildUri(host = null, "stats", "subscribers")

        val buildNavigateAction = statsLinkHandler.buildNavigateAction(uri)

        assertThat(buildNavigateAction).isEqualTo(NavigateAction.OpenStatsForTimeframe(StatsTimeframe.SUBSCRIBERS))
    }

    @Test
    fun `opens stats screen for traffic tab with site when both present in URL`() {
        val siteUrl = "example.com"
        val uri = buildUri(host = null, "stats", "traffic", siteUrl)
        whenever(deepLinkUriUtils.hostToSite(siteUrl)).thenReturn(site)

        val buildNavigateAction = statsLinkHandler.buildNavigateAction(uri)

        assertThat(buildNavigateAction).isEqualTo(
            NavigateAction.OpenStatsForSiteAndTimeframe(
                site,
                StatsTimeframe.TRAFFIC
            )
        )
    }

    @Test
    fun `opens stats screen for subscribers tab with site when both present in URL`() {
        val siteUrl = "example.com"
        val uri = buildUri(host = null, "stats", "subscribers", siteUrl)
        whenever(deepLinkUriUtils.hostToSite(siteUrl)).thenReturn(site)

        val buildNavigateAction = statsLinkHandler.buildNavigateAction(uri)

        assertThat(buildNavigateAction).isEqualTo(
            NavigateAction.OpenStatsForSiteAndTimeframe(
                site,
                StatsTimeframe.SUBSCRIBERS
            )
        )
    }

    @Test
    fun `strips applink with traffic param`() {
        val uri = buildUri(host = "stats", "traffic", "example.com")

        val strippedUrl = statsLinkHandler.stripUrl(uri)

        assertThat(strippedUrl).isEqualTo("wordpress://stats/traffic/domain")
    }

    @Test
    fun `strips applink with subscribers param`() {
        val uri = buildUri(host = "stats", "subscribers", "example.com")

        val strippedUrl = statsLinkHandler.stripUrl(uri)

        assertThat(strippedUrl).isEqualTo("wordpress://stats/subscribers/domain")
    }

    @Test
    fun `strips deeplink with traffic param`() {
        val uri = buildUri(host = "wordpress.com", "stats", "traffic", "example.com")

        val strippedUrl = statsLinkHandler.stripUrl(uri)

        assertThat(strippedUrl).isEqualTo("wordpress.com/stats/traffic/domain")
    }

    @Test
    fun `strips deeplink with subscribers param`() {
        val uri = buildUri(host = "wordpress.com", "stats", "subscribers", "example.com")

        val strippedUrl = statsLinkHandler.stripUrl(uri)

        assertThat(strippedUrl).isEqualTo("wordpress.com/stats/subscribers/domain")
    }
}"}

