506→    data class TopBarUiState(
507→        val menuItems: List<MenuElementData>,
508→        val selectedItem: MenuElementData.Item.Single,
509→        val filterUiState: FilterUiState? = null,
510→        val onDropdownMenuClick: () -> Unit,
511→        val isSearchActionVisible: Boolean = false,
512→    ) {
513→        data class FilterUiState(
514→            val blogsFilterCount: Int,
