import org.assertj.core.api.Assertions.assertThat
import org.junit.Test
import org.wordpress.android.models.ReaderTag
import org.wordpress.android.models.ReaderTagList
import org.wordpress.android.models.ReaderTagType

/**
 * Test to verify that system tags are correctly filtered out
 * to restore the Discover onboarding for new users.
 */
class ReaderDiscoverViewModelTest {

    @Test
    fun `filterOutSystemTags removes dailyprompt tag`() {
        // Create a list with one system tag
        val tags = ReaderTagList()
        tags.add(ReaderTag("dailyprompt", "dailyprompt", "Daily Prompt", "", ReaderTagType.FOLLOWED))

        // Filter out system tags
        val filteredTags = filterOutSystemTags(tags)

        // Verify that the result is empty
        assertThat(filteredTags).isEmpty()
    }

    @Test
    fun `filterOutSystemTags keeps non-system tags`() {
        // Create a list with system and non-system tags
        val tags = ReaderTagList()
        tags.add(ReaderTag("dailyprompt", "dailyprompt", "Daily Prompt", "", ReaderTagType.FOLLOWED))
        tags.add(ReaderTag("technology", "technology", "Technology", "", ReaderTagType.FOLLOWED))
        tags.add(ReaderTag("travel", "travel", "Travel", "", ReaderTagType.FOLLOWED))

        // Filter out system tags
        val filteredTags = filterOutSystemTags(tags)

        // Verify that only non-system tags remain
        assertThat(filteredTags).hasSize(2)
        assertThat(filteredTags[0].tagSlug).isEqualTo("technology")
        assertThat(filteredTags[1].tagSlug).isEqualTo("travel")
    }

    @Test
    fun `filterOutSystemTags handles empty list`() {
        // Create an empty list
        val tags = ReaderTagList()

        // Filter out system tags
        val filteredTags = filterOutSystemTags(tags)

        // Verify that the result is empty
        assertThat(filteredTags).isEmpty()
    }

    @Test
    fun `filterOutSystemTags handles only system tags`() {
        // Create a list with only system tags
        val tags = ReaderTagList()
        tags.add(ReaderTag("dailyprompt", "dailyprompt", "Daily Prompt", "", ReaderTagType.FOLLOWED))
        tags.add(ReaderTag("dailyprompt-123", "dailyprompt-123", "Daily Prompt 123", "", ReaderTagType.FOLLOWED))

        // Filter out system tags - only "dailyprompt" is filtered, "dailyprompt-123" should remain
        val filteredTags = filterOutSystemTags(tags)

        // Verify that only dailyprompt-123 remains (it's not in the SYSTEM_TAGS list)
        // Note: The system only filters "dailyprompt", not "dailyprompt-123"
        assertThat(filteredTags).hasSize(1)
        assertThat(filteredTags[0].tagSlug).isEqualTo("dailyprompt-123")
    }

    /**
     * Replicates the private filterOutSystemTags logic from ReaderDiscoverViewModel for testing purposes.
     * This is a copy of the implementation in the actual class.
     */
    private fun filterOutSystemTags(tags: ReaderTagList): ReaderTagList {
        val systemTags = listOf("dailyprompt")
        val filteredList = ReaderTagList()
        tags.forEach { tag ->
            if (!systemTags.contains(tag.tagSlug)) {
                filteredList.add(tag)
            }
        }
        return filteredList
    }
}"}

