class ReaderTopBarMenuHelperNewBehaviorTest {
    private val readerTagsFeedFeatureConfig: ReaderTagsFeedFeatureConfig = mock()
    val helper = ReaderTopBarMenuHelper(
        readerTagsFeedFeatureConfig = readerTagsFeedFeatureConfig
    )

    @Test
    fun `GIVEN 0 custom lists WHEN createMenu THEN no divider and no items are added`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
        }

        val menu = helper.createMenu(tags)

        assertThat(menu).doesNotContain(MenuElementData.Divider)
        assertThat(menu.findSubMenu()).isNull()
    }

    @Test
    fun `GIVEN 1 custom list WHEN createMenu THEN list appears directly in menu root, not in submenu`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("my-single-list")) // item 2
        }

        val menu = helper.createMenu(tags)

        // Contains divider before custom lists
        assertThat(menu).contains(MenuElementData.Divider)

        // Should not have a submenu
        assertThat(menu.findSubMenu()).isNull()

        // The single list should be a direct item
        val customListItem = menu.findSingleItem { it.text == UiStringText("my-single-list") }
        assertThat(customListItem).isNotNull()
        assertThat(customListItem?.id).isEqualTo("2")
    }

    @Test
    fun `GIVEN 2 custom lists WHEN createMenu THEN both lists appear directly in menu root, not in submenu`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("list-one")) // item 2
            add(createCustomListTag("list-two")) // item 3
        }

        val menu = helper.createMenu(tags)

        // Contains divider before custom lists
        assertThat(menu).contains(MenuElementData.Divider)

        // Should not have a submenu
        assertThat(menu.findSubMenu()).isNull()

        // Both lists should be direct items
        val listOneItem = menu.findSingleItem { it.text == UiStringText("list-one") }
        assertThat(listOneItem).isNotNull()
        assertThat(listOneItem?.id).isEqualTo("2")

        val listTwoItem = menu.findSingleItem { it.text == UiStringText("list-two") }
        assertThat(listTwoItem).isNotNull()
        assertThat(listTwoItem?.id).isEqualTo("3")
    }

    @Test
    fun `GIVEN 3 custom lists WHEN createMenu THEN lists appear in submenu`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

