            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
            add(createCustomListTag("list-one")) // item 2
            add(createCustomListTag("list-two")) // item 3
            add(createCustomListTag("list-three")) // item 4
        }

        val menu = helper.createMenu(tags)

        // Contains divider before custom lists
        assertThat(menu).contains(MenuElementData.Divider)

        // Should have a submenu
        val subMenu = menu.findSubMenu()
        assertThat(subMenu).isNotNull()

        // Submenu has correct title
        assertThat(subMenu?.text).isEqualTo(UiStringRes(R.string.reader_dropdown_menu_lists))

        // All lists should be children of submenu
        val listOneItem = subMenu?.children?.findSingleItem { it.text == UiStringText("list-one") }
        assertThat(listOneItem?.id).isEqualTo("2")

        val listTwoItem = subMenu?.children?.findSingleItem { it.text == UiStringText("list-two") }
        assertThat(listTwoItem?.id).isEqualTo("3")

        val listThreeItem = subMenu?.children?.findSingleItem { it.text == UiStringText("list-three") }
        assertThat(listThreeItem?.id).isEqualTo("4")
    }

    @Test
    fun `GIVEN 4 custom lists WHEN createMenu THEN lists appear in submenu`() {
        whenever(readerTagsFeedFeatureConfig.isEnabled()).thenReturn(false)

        val tags = ReaderTagList().apply {
            add(mockDiscoverTag()) // item 0
            add(mockFollowingTag()) // item 1
