{"file_path":"/project/WordPress/src/main/java/org/wordpress/android/ui/posts/prepublishing/home/PrepublishingHomeViewModel.kt","content":"package org.wordpress.android.ui.posts.prepublishing.home

import androidx.lifecycle.LiveData
import androidx.lifecycle.MutableLiveData
import kotlinx.coroutines.CoroutineDispatcher
import kotlinx.coroutines.Job
import kotlinx.coroutines.delay
import org.wordpress.android.R
import org.wordpress.android.analytics.AnalyticsTracker
import org.wordpress.android.fluxc.model.SiteModel
import org.wordpress.android.fluxc.model.post.PostStatus
import org.wordpress.android.modules.BG_THREAD
import org.wordpress.android.ui.posts.EditPostRepository
import org.wordpress.android.ui.posts.EditorJetpackSocialViewModel
import org.wordpress.android.ui.posts.GetCategoriesUseCase
import org.wordpress.android.ui.posts.GetPostTagsUseCase
import org.wordpress.android.ui.posts.PostSettingsUtils
import org.wordpress.android.ui.posts.prepublishing.home.PrepublishingHomeItemUiState.ActionType
import org.wordpress.android.ui.posts.prepublishing.home.PrepublishingHomeItemUiState.ActionType.PrepublishingScreenNavigation
import org.wordpress.android.ui.posts.prepublishing.home.PrepublishingHomeItemUiState.HeaderUiState
import org.wordpress.android.ui.posts.prepublishing.home.PrepublishingHomeItemUiState.HomeUiState
import org.wordpress.android.ui.posts.prepublishing.home.PrepublishingHomeItemUiState.SocialUiState
import org.wordpress.android.ui.posts.prepublishing.home.PrepublishingHomeItemUiState.StoryTitleUiState
import org.wordpress.android.ui.posts.prepublishing.home.usecases.GetButtonUiStateUseCase
import org.wordpress.android.ui.posts.trackPrepublishingNudges
import org.wordpress.android.ui.stories.StoryRepositoryWrapper
import org.wordpress.android.ui.stories.usecase.UpdateStoryPostTitleUseCase
import org.wordpress.android.ui.utils.UiString.UiStringRes
import org.wordpress.android.ui.utils.UiString.UiStringText
import org.wordpress.android.util.StringUtils
import org.wordpress.android.util.analytics.AnalyticsTrackerWrapper
import org.wordpress.android.util.merge
import org.wordpress.android.viewmodel.Event
import org.wordpress.android.viewmodel.ScopedViewModel
import javax.inject.Inject
import javax.inject.Named

private const val THROTTLE_DELAY = 500L

class PrepublishingHomeViewModel @Inject constructor(
    private val getPostTagsUseCase: GetPostTagsUseCase,
    private val postSettingsUtils: PostSettingsUtils,
    private val getButtonUiStateUseCase: GetButtonUiStateUseCase,
    private val analyticsTrackerWrapper: AnalyticsTrackerWrapper,
    private val storyRepositoryWrapper: StoryRepositoryWrapper,
    private val updateStoryPostTitleUseCase: UpdateStoryPostTitleUseCase,
    private val getCategoriesUseCase: GetCategoriesUseCase,
    @Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher
) : ScopedViewModel(bgDispatcher) {
    private var isStarted = false
    private var updateStoryTitleJob: Job? = null
    private lateinit var editPostRepository: EditPostRepository

    private val _storyTitleUiState = MutableLiveData<StoryTitleUiState>()
    val storyTitleUiState: LiveData<StoryTitleUiState> = _storyTitleUiState

    private val _onActionClicked = MutableLiveData<Event<ActionType>>()
    val onActionClicked: LiveData<Event<ActionType>> = _onActionClicked

    private val _onSubmitButtonClicked = MutableLiveData<Event<PublishPost>>()
    val onSubmitButtonClicked: LiveData<Event<PublishPost>> = _onSubmitButtonClicked

    private val _uiState = MutableLiveData<List<PrepublishingHomeItemUiState>>()
    private var _socialUiState: MutableLiveData<SocialUiState> = MutableLiveData(SocialUiState.Hidden)

    val uiState: LiveData<List<PrepublishingHomeItemUiState>> = merge(
        _uiState,
        _socialUiState
    ) { list, socialUiState ->
        list?.map { item ->
            if (item is SocialUiState) {
                socialUiState ?: SocialUiState.Hidden
            } else {
                item
            }
        }
    }

    fun start(editPostRepository: EditPostRepository, site: SiteModel, isStoryPost: Boolean) {
        this.editPostRepository = editPostRepository
        if (isStarted) return
        isStarted = true

        setupHomeUiState(editPostRepository, site, isStoryPost)
    }

    private fun setupHomeUiState(
        editPostRepository: EditPostRepository,
        site: SiteModel,
        isStoryPost: Boolean
    ) {
        val prepublishingHomeUiStateList = mutableListOf<PrepublishingHomeItemUiState>().apply {
            if (isStoryPost) {
                _storyTitleUiState.postValue(StoryTitleUiState(
                    storyTitle = UiStringText(StringUtils.notNullStr(editPostRepository.title)),
                    storyThumbnailUrl = storyRepositoryWrapper.getCurrentStoryThumbnailUrl()
                ) { storyTitle ->
                    onStoryTitleChanged(storyTitle)
                })
            } else {
                add(
                    HeaderUiState(
                        UiStringText(site.name),
                        StringUtils.notNullStr(site.iconUrl)
                    )
                )
            }

            if (editPostRepository.status != PostStatus.PRIVATE) {
                showPublicPost(editPostRepository)
            } else {
                showPrivatePost(editPostRepository)
            }

            if (!editPostRepository.isPage) {
                showNotSetPost(editPostRepository, site)

                val categoriesString = getCategoriesUseCase.getPostCategoriesString(
                    editPostRepository,
                    site
                )

                add(HomeUiState(
                    navigationAction = PrepublishingScreenNavigation.Categories,
                    actionResult = if (categoriesString.isNotEmpty()) {
                        UiStringText(categoriesString)
                    } else {
                        run { UiStringRes(R.string.prepublishing_nudges_home_categories_not_set) }
                    },
                    actionClickable = true,
                    onNavigationActionClicked = ::onActionClicked
                ))
            }

            add(SocialUiState.Hidden)

            add(getButtonUiStateUseCase.getUiState(editPostRepository, site) { publishPost ->
                launch(bgDispatcher) {
                    waitForStoryTitleJobAndSubmit(publishPost)
                }
            })
        }.toList()

        _uiState.postValue(prepublishingHomeUiStateList)
    }

    private fun MutableList<PrepublishingHomeItemUiState>.showNotSetPost(
        editPostRepository: EditPostRepository,
        site: SiteModel
    ) {
        add(
            HomeUiState(
                navigationAction = PrepublishingScreenNavigation.Tags,
                actionResult = getPostTagsUseCase.getTags(editPostRepository)
                    ?.let { UiStringText(it) }
                    ?: run { UiStringRes(R.string.prepublishing_nudges_home_tags_not_set) },
                actionClickable = true,
                onNavigationActionClicked = ::onActionClicked
            )
        )

        val categoryString: String = getCategoriesUseCase.getPostCategoriesString(
            editPostRepository,
            site
        )
        if (categoryString.isNotEmpty()) {
            UiStringText(categoryString)
        }
    }

    private fun MutableList<PrepublishingHomeItemUiState>.showPrivatePost(
        editPostRepository: EditPostRepository
    ) {
        add(
            HomeUiState(
                navigationAction = PrepublishingScreenNavigation.Publish,
                actionResult = editPostRepository.getEditablePost()
                    ?.let {
                        UiStringText(
                            postSettingsUtils.getPublishDateLabel(
                                it
                            )
                        )
                    },
                actionTypeColor = R.color.prepublishing_action_type_disabled_color,
                actionResultColor = R.color.prepublishing_action_result_disabled_color,
                actionClickable = false,
                onNavigationActionClicked = null
            )
        )
    }

    private fun MutableList<PrepublishingHomeItemUiState>.showPublicPost(
        editPostRepository: EditPostRepository
    ) {
        add(
            HomeUiState(
                navigationAction = PrepublishingScreenNavigation.Publish,
                actionResult = editPostRepository.getEditablePost()
                    ?.let {
                        UiStringText(
                            postSettingsUtils.getPublishDateLabel(
                                it
                            )
                        )
                    },
                actionClickable = true,
                onNavigationActionClicked = ::onActionClicked
            )
        )
    }

    private fun onStoryTitleChanged(storyTitle: String) {
        updateStoryTitleJob?.cancel()
        updateStoryTitleJob = launch(bgDispatcher) {
            // there's a delay here since every single character change event triggers onStoryTitleChanged
            // and without a delay we would have multiple save operations being triggered unnecessarily.
            delay(THROTTLE_DELAY)
            storyRepositoryWrapper.setCurrentStoryTitle(storyTitle)
            updateStoryPostTitleUseCase.updateStoryTitle(storyTitle, editPostRepository)
        }
    }

    private suspend fun waitForStoryTitleJobAndSubmit(publishPost: PublishPost) {
        updateStoryTitleJob?.join()
        analyticsTrackerWrapper.trackPrepublishingNudges(AnalyticsTracker.Stat.EDITOR_POST_PUBLISH_NOW_TAPPED)
        _onSubmitButtonClicked.postValue(Event(publishPost))
    }

    override fun onCleared() {
        super.onCleared()
        updateStoryTitleJob?.cancel()
    }

    private fun onActionClicked(actionType: ActionType) {
        _onActionClicked.postValue(Event(actionType))
    }

    fun updateJetpackSocialState(
        state: EditorJetpackSocialViewModel.JetpackSocialUiState?
    ) {
        val isPostPublished = editPostRepository.getPost()?.status == PostStatus.PUBLISHED.toString()
        val newState = state?.takeUnless { isPostPublished }?.let {
            SocialUiState.Visible(
                it,
                onItemClicked = { onActionClicked(PrepublishingScreenNavigation.Social) }
            )
        } ?: SocialUiState.Hidden

        _socialUiState.postValue(newState)
    }
}"}

{"file_path":"/project/WordPress/src/test/java/org/wordpress/android/ui/posts/prepublishing/home/PrepublishingHomeViewModelPageCategoriesTest.kt","content":"package org.wordpress.android.ui.posts.prepublishing.home

import kotlinx.coroutines.ExperimentalCoroutinesApi
import org.assertj.core.api.Assertions.assertThat
import org.junit.Before
import org.junit.Test
import org.mockito.Mock
import org.mockito.kotlin.any
import org.mockito.kotlin.mock
import org.mockito.kotlin.whenever
import org.wordpress.android.BaseUnitTest
import org.wordpress.android.fluxc.model.SiteModel
import org.wordpress.android.fluxc.model.post.PostStatus
import org.wordpress.android.ui.posts.EditPostRepository
import org.wordpress.android.ui.posts.PostSettingsUtils
import org.wordpress.android.ui.posts.GetCategoriesUseCase
import org.wordpress.android.ui.posts.GetPostTagsUseCase
import org.wordpress.android.ui.posts.prepublishing.home.usecases.GetButtonUiStateUseCase
import org.wordpress.android.ui.stories.StoryRepositoryWrapper
import org.wordpress.android.ui.stories.usecase.UpdateStoryPostTitleUseCase

/**
 * Test to verify that pages do NOT show categories in the prepublishing modal.
 * This test validates the fix for the issue where pages incorrectly displayed
 * a prepublishing modal with category selection options.
 */
@ExperimentalCoroutinesApi
class PrepublishingHomeViewModelPageCategoriesTest : BaseUnitTest() {
    private lateinit var viewModel: PrepublishingHomeViewModel

    @Mock
    lateinit var postSettingsUtils: PostSettingsUtils

    @Mock
    lateinit var editPostRepository: EditPostRepository

    @Mock
    lateinit var getPostTagsUseCase: GetPostTagsUseCase

    @Mock
    lateinit var getButtonUiStateUseCase: GetButtonUiStateUseCase

    @Mock
    lateinit var storyRepositoryWrapper: StoryRepositoryWrapper

    @Mock
    lateinit var updateStoryTitleUseCase: UpdateStoryPostTitleUseCase

    @Mock
    lateinit var getCategoriesUseCase: GetCategoriesUseCase

    @Mock
    lateinit var site: SiteModel

    @Before
    @Suppress("UNCHECKED_CAST")
    fun setUp() {
        viewModel = PrepublishingHomeViewModel(
            getPostTagsUseCase,
            postSettingsUtils,
            getButtonUiStateUseCase,
            mock(),
            storyRepositoryWrapper,
            updateStoryTitleUseCase,
            getCategoriesUseCase,
            testDispatcher()
        )
        whenever(
            getButtonUiStateUseCase.getUiState(
                any(),
                any(),
                any()
            )
        ).doAnswer {
            PrepublishingHomeItemUiState.PublishButtonUiState(it.arguments[2] as (PublishPost) -> Unit)
        }
        whenever(editPostRepository.getEditablePost()).thenReturn(org.wordpress.android.fluxc.model.PostModel())
        whenever(editPostRepository.title).thenReturn("")
        whenever(postSettingsUtils.getPublishDateLabel(any())).thenReturn((""))
        whenever(site.name).thenReturn("")
        whenever(storyRepositoryWrapper.getCurrentStoryThumbnailUrl()).thenReturn("")
        whenever(getCategoriesUseCase.getPostCategoriesString(any(), any())).thenReturn("")

        // need to observe forever to be able to access `value` since it's a MediatorLiveData
        viewModel.uiState.observeForever(mock())
    }

    @Test
    fun `verify that categories actions is not propagated to prepublishingHomeUiState when post is a page`() {
        // arrange
        whenever(editPostRepository.isPage).thenReturn(true)

        // act
        viewModel.start(editPostRepository, site, false)

        // assert
        assertThat(getHomeUiState(PrepublishingScreenNavigation.Categories)).isNull()
    }

    @Test
    fun `verify that categories actions is propagated to prepublishingHomeUiState when post is not a page`() {
        // arrange
        whenever(editPostRepository.isPage).thenReturn(false)

        // act
        viewModel.start(editPostRepository, site, false)

        // assert
        assertThat(getHomeUiState(PrepublishingScreenNavigation.Categories)).isNotNull()
    }

    @Test
    fun `verify that page has only Publish action and no Tags or Categories actions`() {
        // arrange
        whenever(editPostRepository.isPage).thenReturn(true)
        whenever(editPostRepository.status).thenReturn(PostStatus.PUBLISHED)

        // act
        viewModel.start(editPostRepository, site, false)

        // assert
        assertThat(getHomeUiState(PrepublishingScreenNavigation.Tags)).isNull()
        assertThat(getHomeUiState(PrepublishingScreenNavigation.Categories)).isNull()
        assertThat(getHomeUiState(PrepublishingScreenNavigation.Publish)).isNotNull()
    }

    @Test
