import org.wordpress.android.util.LocaleManagerWrapper
import org.wordpress.android.util.text.PercentFormatter
import org.wordpress.android.viewmodel.ResourceProvider
import java.util.Locale

/**
 * Test to verify that infinite percentages (∞) don't show "(∞)" in the output.
 * When the percentage is infinite, we should only show the absolute change.
 *
 * Related issue: "(∞)" shouldn't be used for infinite percentages in stats screens
 */
@RunWith(MockitoJUnitRunner::class)
class InfinitePercentageFixTest {
    @Mock
    lateinit var resourceProvider: ResourceProvider

    @Mock
    lateinit var localeManagerWrapper: LocaleManagerWrapper

    @Mock
    private lateinit var percentFormatter: PercentFormatter
    private lateinit var statsUtils: StatsUtils

    @Before
    fun setUp() {
        statsUtils = StatsUtils(resourceProvider, localeManagerWrapper, percentFormatter)
        whenever(localeManagerWrapper.getLocale()).thenReturn(Locale.US)
        whenever(resourceProvider.getString(any(), any())).then {
            val resourceId = it.getArgument<Int>(0)
            val value = it.getArgument<String>(1)
            when (resourceId) {
                R.string.negative_prefix -> "-$value"
                R.string.suffix_1_000 -> value + "k"
                R.string.suffix_1_000_000 -> value + "M"
                R.string.suffix_1_000_000_000 -> value + "B"
                R.string.stats_traffic_increase -> "+$value"
                R.string.stats_traffic_increase, R.string.stats_traffic_change -> it.arguments[1].toString()
                else -> value
            }
        }
    }

    /**
     * Test that when previousValue is 0 and current value is positive,
     * the output should only show the increase without "(∞)".
     *
     * Expected: "+5" (not "+5 (∞)")
     */
    @Test
    fun `buildChange with infinite positive difference should not show percentage in parentheses`() {
        val previousValue = 0L
        val value = 5L
        val positive = true

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = false)

        // Should return "+5" without the "(∞)" part
        assertThat(change).isEqualTo("+5")
    }

    /**
     * Test that when previousValue is 0 and current value is negative,
     * the output should only show the absolute value without "(∞)".
     */
    @Test
    fun `buildChange with infinite negative difference should not show percentage in parentheses`() {
        val previousValue = 0L
        val value = -5L
        val positive = false

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = false)

        // Should return "-5" without the "(∞)" part
        assertThat(change).isEqualTo("-5")
    }

    /**
     * Test normal percentage calculation is not affected by the fix.
     */
    @Test
    fun `buildChange with normal percentage should include percentage in parentheses`() {
        val previousValue = 5L
        val value = 20L
        val positive = true
        val expectedChange = "+15 (300%)"

        whenever(resourceProvider.getString(eq(R.string.stats_traffic_increase), eq("15"), eq("300")))
            .thenReturn(expectedChange)

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = true)

        assertThat(change).isEqualTo(expectedChange)
    }

    /**
     * Test with formatted numbers (using "k", "M" suffixes).
     */
    @Test
    fun `buildChange with infinite percentage and formatted numbers should not show percentage`() {
        val previousValue = 0L
        val value = 20000L  // Should format to "20k"
        val positive = true

        val change = statsUtils.buildChange(previousValue, value, positive, isFormattedNumber = true)

        // Should return "+20k" without the "(∞)" part
        assertThat(change).isEqualTo("+20k")
    }
}"}

