                R.string.suffix_1_000_000_000_000 -> value + suffixTrillion
                else -> value
            }
        }
    }

    @Test
    fun `test stats int formatter`() {
        val numbers: List<Int> = listOf(
            0,
            5,
            999,
            1000,
            -5821,
