            -101800,
            2000000,
            -7800000,
            92150000,
            1232000000
        )
        val expected = listOf(
            "0",
            "5",
            "999",
            "1,000",
            "-5,821",
            "10k",
            "-101k",
            "2M",
            "-7.8M",
            "92M",
            "1.2B"
        )
        for (i in numbers.indices) {
