 26→
 27→    static ReaderTagFragment newInstance() {
 28→        AppLog.d(AppLog.T.READER, "reader tag list > newInstance");
 29→        return new ReaderTagFragment();
 30→    }
 31→
 32→    @Override
 33→    public View onCreateView(@NonNull LayoutInflater inflater, ViewGroup container, Bundle savedInstanceState) {
 34→        View view = inflater.inflate(R.layout.reader_fragment_list, container, false);
 35→        mRecyclerView = view.findViewById(R.id.recycler_view);
 36→        return view;
 37→    }
 38→
 39→    private void checkEmptyView() {
 40→        if (!isAdded() || getView() == null) {
 41→            return;
 42→        }
 43→
 44→        ActionableEmptyView actionableEmptyView = getView().findViewById(R.id.actionable_empty_view);
 45→
 46→        if (actionableEmptyView == null) {
 47→            return;
 48→        }
 49→
 50→        actionableEmptyView.image.setImageResource(R.drawable.img_illustration_empty_results_216dp);
 51→        actionableEmptyView.image.setVisibility(View.VISIBLE);
 52→        actionableEmptyView.title.setText(R.string.reader_empty_followed_tags_title);
 53→        actionableEmptyView.subtitle.setText(R.string.reader_empty_followed_tags_subtitle);
 54→        actionableEmptyView.subtitle.setVisibility(View.VISIBLE);
 55→        actionableEmptyView.setVisibility(hasTagAdapter() && getTagAdapter().isEmpty() ? View.VISIBLE : View.GONE);
 56→    }
 57→
 58→    @Override
 59→    @SuppressWarnings("deprecation")
 60→    public void onActivityCreated(Bundle savedInstanceState) {
 61→        super.onActivityCreated(savedInstanceState);
 62→        mRecyclerView.setAdapter(getTagAdapter());
 63→        refresh();
 64→    }
 65→
 66→    void refresh() {
 67→        if (hasTagAdapter()) {
 68→            AppLog.d(AppLog.T.READER, "reader subs > refreshing tag fragment");
 69→            getTagAdapter().refresh();
 70→        }
 71→    }
 72→
 73→    private ReaderTagAdapter getTagAdapter() {
 74→        if (mTagAdapter == null) {
 75→            Context context = WPActivityUtils.getThemedContext(getActivity());
 76→            mTagAdapter = new ReaderTagAdapter(context);
 77→            mTagAdapter.setTagDeletedListener(this);
 78→            mTagAdapter.setDataLoadedListener(new ReaderInterfaces.DataLoadedListener() {
 79→                @Override
 80→                public void onDataLoaded(boolean isEmpty) {
 81→                    checkEmptyView();
 82→                }
 83→            });
 84→        }
 85→        return mTagAdapter;
 86→    }
 87→
 88→    private boolean hasTagAdapter() {
 89→        return (mTagAdapter != null);
 90→    }
 91→
 92→    /*
 93→     * called from adapter when user removes a tag - note that the network request
 94→     * has been made by the time this is called
 95→     */
 96→    @Override
 97→    public void onTagDeleted(ReaderTag tag) {
 98→        checkEmptyView();
 99→        // let the host activity know about the change
100→        if (getActivity() instanceof ReaderTagAdapter.TagDeletedListener) {
101→            ((ReaderTagAdapter.TagDeletedListener) getActivity()).onTagDeleted(tag);
102→        }
103→    }
104→}
